def clamp(value, maximum):
    if value > maximum:
        return maximum
    return value

print(clamp(120, 100))

for token in ["443", "ssh", "22"]:
    try:
        print(int(token))
    except ValueError:
        print(f"not a number: {token}")

def count_entries(log):
    return len(log.split("\n"))

sample = "GET /login 200\nGET /admin 403\nPOST /login 200"
print(count_entries(sample))
